from flask import Flask, request, jsonify
import redis
import re

app = Flask(__name__)

redis_client = redis.Redis(host='localhost', port=6379, decode_responses=True)

ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'KEYS', 
    'HGET', 'HSET', 'HDEL', 'HGETALL', 'HKEYS', 'HVALS',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LRANGE', 'LLEN',
    'SADD', 'SREM', 'SMEMBERS', 'SISMEMBER',
    'ZADD', 'ZREM', 'ZRANGE', 'ZCARD',
    'INCR', 'DECR', 'INCRBY', 'DECRBY',
    'MGET', 'MSET', 'STRLEN', 'APPEND',
    'PING', 'ECHO', 'INFO', 'DBSIZE', 'TYPE'
}

DANGEROUS_COMMANDS = {
    'FLUSHDB', 'FLUSHALL', 'CONFIG', 'SHUTDOWN', 'BGREWRITEAOF',
    'BGSAVE', 'SAVE', 'DEBUG', 'SLAVEOF', 'REPLICAOF', 'SYNC',
    'PSYNC', 'MIGRATE', 'RESTORE', 'SCRIPT', 'EVAL', 'EVALSHA',
    'CLIENT', 'CLUSTER', 'READONLY', 'READWRITE', 'ACL',
    'ROLE', 'MONITOR', 'SLOWLOG', 'LATENCY', 'MODULE'
}

def validate_command(command_str):
    if not command_str or not isinstance(command_str, str):
        return False, "Invalid command format"
    
    command_str = command_str.strip()
    
    if len(command_str) > 1000:
        return False, "Command too long"
    
    parts = command_str.split()
    if not parts:
        return False, "Empty command"
    
    cmd = parts[0].upper()
    
    if cmd in DANGEROUS_COMMANDS:
        return False, f"Command '{cmd}' is not allowed for security reasons"
    
    if cmd not in ALLOWED_COMMANDS:
        return False, f"Command '{cmd}' is not in the allowed list"
    
    dangerous_patterns = [
        r'--',
        r';',
        r'\|',
        r'&',
        r'\$\(',
        r'`',
        r'\n',
        r'\r'
    ]
    
    for pattern in dangerous_patterns:
        if re.search(pattern, command_str):
            return False, "Command contains forbidden characters"
    
    return True, "Valid"

def parse_command(command_str):
    parts = []
    current = []
    in_quotes = False
    quote_char = None
    
    i = 0
    while i < len(command_str):
        char = command_str[i]
        
        if char in ('"', "'") and not in_quotes:
            in_quotes = True
            quote_char = char
            i += 1
            continue
        elif char == quote_char and in_quotes:
            in_quotes = False
            quote_char = None
            i += 1
            continue
        elif char == ' ' and not in_quotes:
            if current:
                parts.append(''.join(current))
                current = []
            i += 1
            continue
        
        current.append(char)
        i += 1
    
    if current:
        parts.append(''.join(current))
    
    return parts

@app.route('/admin/redis', methods=['GET', 'POST'])
def execute_redis_command():
    try:
        if request.method == 'GET':
            command_str = request.args.get('command', '')
        else:
            command_str = request.json.get('command', '') if request.is_json else request.form.get('command', '')
        
        is_valid, message = validate_command(command_str)
        if not is_valid:
            return jsonify({
                'success': False,
                'error': message
            }), 400
        
        command_parts = parse_command(command_str)
        
        result = redis_client.execute_command(*command_parts)
        
        if isinstance(result, bytes):
            result = result.decode('utf-8')
        elif isinstance(result, list):
            result = [item.decode('utf-8') if isinstance(item, bytes) else item for item in result]
        elif isinstance(result, dict):
            result = {k.decode('utf-8') if isinstance(k, bytes) else k: 
                     v.decode('utf-8') if isinstance(v, bytes) else v 
                     for k, v in result.items()}
        
        return jsonify({
            'success': True,
            'command': command_str,
            'result': result
        }), 200
        
    except redis.exceptions.ResponseError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}'
        }), 400
    except redis.exceptions.ConnectionError as e:
        return jsonify({
            'success': False,
            'error': 'Failed to connect to Redis'
        }), 503
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Unexpected error: {str(e)}'
        }), 500

@app.route('/admin/redis/allowed-commands', methods=['GET'])
def get_allowed_commands():
    return jsonify({
        'allowed_commands': sorted(list(ALLOWED_COMMANDS)),
        'dangerous_commands': sorted(list(DANGEROUS_COMMANDS))
    }), 200

@app.route('/health', methods=['GET'])
def health_check():
    try:
        redis_client.ping()
        return jsonify({'status': 'healthy', 'redis': 'connected'}), 200
    except:
        return jsonify({'status': 'unhealthy', 'redis': 'disconnected'}), 503

if __name__ == '__main__':
    app.run(debug=False, host='127.0.0.1', port=5000)